function requireScope(scope:string) {
  return (req,res,next) => {
    const scopes = req.user?.scopes ?? ['all'];
    if (scopes.includes(scope) || scopes.includes('all')) return next();
    res.status(403).json({error:'insufficient_scope'});
  };
}
